// // This module converts a 4-bit binary number to its corresponding 4-bit gray code representation.
module bin2gray_4bit(
    input [3:0] bin, 
    output [3:0] gray);

    assign gray[3] = bin[3];
    assign gray[2] = bin[3] ^ bin[2];
    assign gray[1] = bin[2] ^ bin[1];
    assign gray[0] = bin[1] ^ bin[0];
endmodule
